import { useState } from 'react';

function CategoryManager({ categories, setCategories }) {
  const [form, setForm] = useState({ large: '', medium: '', small: '' });
  const [editIndex, setEditIndex] = useState(null);
  const [openLarge, setOpenLarge] = useState(null);
  const [openMedium, setOpenMedium] = useState(null);

  const handleAddLarge = () => {
    if (!form.large.trim()) { alert('대분류를 입력해주세요!'); return; }
    if (categories.find((c) => c.name === form.large.trim())) { alert('이미 있는 대분류예요!'); return; }
    setCategories([...categories, { name: form.large.trim(), children: [] }]);
    setForm({ ...form, large: '' });
  };

  const handleDeleteLarge = (largeName) => {
    if (window.confirm(`'${largeName}' 대분류를 삭제할까요? 하위 카테고리도 모두 삭제돼요!`)) {
      setCategories(categories.filter((c) => c.name !== largeName));
      setOpenLarge(null);
    }
  };

  const handleAddMedium = (largeName) => {
    if (!form.medium.trim()) { alert('중분류를 입력해주세요!'); return; }
    setCategories(categories.map((c) =>
      c.name === largeName
        ? { ...c, children: [...c.children, { name: form.medium.trim(), children: [] }] }
        : c
    ));
    setForm({ ...form, medium: '' });
  };

  const handleDeleteMedium = (largeName, mediumName) => {
    if (window.confirm(`'${mediumName}' 중분류를 삭제할까요?`)) {
      setCategories(categories.map((c) =>
        c.name === largeName
          ? { ...c, children: c.children.filter((m) => m.name !== mediumName) }
          : c
      ));
      setOpenMedium(null);
    }
  };

  const handleAddSmall = (largeName, mediumName) => {
    if (!form.small.trim()) { alert('소분류를 입력해주세요!'); return; }
    setCategories(categories.map((c) =>
      c.name === largeName
        ? {
            ...c, children: c.children.map((m) =>
              m.name === mediumName
                ? { ...m, children: [...m.children, form.small.trim()] }
                : m
            )
          }
        : c
    ));
    setForm({ ...form, small: '' });
  };

  const handleDeleteSmall = (largeName, mediumName, smallName) => {
    if (window.confirm(`'${smallName}' 소분류를 삭제할까요?`)) {
      setCategories(categories.map((c) =>
        c.name === largeName
          ? {
              ...c, children: c.children.map((m) =>
                m.name === mediumName
                  ? { ...m, children: m.children.filter((s) => s !== smallName) }
                  : m
              )
            }
          : c
      ));
    }
  };

  return (
    <div style={{ padding: '24px', maxWidth: '900px', margin: '0 auto' }}>
      <h2 style={{ marginBottom: '24px', color: '#1b5e20' }}>📂 카테고리 관리</h2>

      {/* 대분류 추가 */}
      <div style={{ background: '#f1f8e9', padding: '20px', borderRadius: '12px', marginBottom: '24px', border: '1px solid #c8e6c9' }}>
        <h3 style={{ marginBottom: '12px', color: '#2e7d32' }}>대분류 추가</h3>
        <div style={{ display: 'flex', gap: '8px' }}>
          <input
            value={form.large}
            onChange={(e) => setForm({ ...form, large: e.target.value })}
            placeholder="대분류 이름 (예: 식품)"
            style={{ flex: 1, padding: '10px', borderRadius: '8px', border: '1px solid #c8e6c9', fontSize: '14px' }}
          />
          <button onClick={handleAddLarge} style={{ padding: '10px 20px', background: '#2e7d32', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>
            추가
          </button>
        </div>
      </div>

      {/* 카테고리 목록 */}
      {categories.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '40px', color: '#888', background: 'white', borderRadius: '12px', border: '1px solid #e0e0e0' }}>
          <p style={{ fontSize: '32px', margin: '0 0 8px' }}>📂</p>
          <p>아직 카테고리가 없어요. 대분류를 추가해주세요!</p>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {categories.map((large) => (
            <div key={large.name} style={{ background: 'white', borderRadius: '12px', border: '1px solid #e0e0e0', overflow: 'hidden' }}>

              {/* 대분류 헤더 */}
              <div style={{ background: '#2e7d32', color: 'white', padding: '12px 16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span
                  style={{ fontWeight: 'bold', cursor: 'pointer', fontSize: '15px' }}
                  onClick={() => setOpenLarge(openLarge === large.name ? null : large.name)}
                >
                  {openLarge === large.name ? '▼' : '▶'} 📁 {large.name}
                </span>
                <button onClick={() => handleDeleteLarge(large.name)} style={{ background: '#e53935', color: 'white', border: 'none', borderRadius: '6px', padding: '5px 12px', cursor: 'pointer', fontSize: '12px' }}>
                  삭제
                </button>
              </div>

              {openLarge === large.name && (
                <div style={{ padding: '16px' }}>

                  {/* 중분류 추가 */}
                  <div style={{ display: 'flex', gap: '8px', marginBottom: '12px' }}>
                    <input
                      value={form.medium}
                      onChange={(e) => setForm({ ...form, medium: e.target.value })}
                      placeholder="중분류 이름 (예: 신선식품)"
                      style={{ flex: 1, padding: '8px 12px', borderRadius: '8px', border: '1px solid #c8e6c9', fontSize: '13px' }}
                    />
                    <button onClick={() => handleAddMedium(large.name)} style={{ padding: '8px 16px', background: '#388e3c', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '13px' }}>
                      중분류 추가
                    </button>
                  </div>

                  {/* 중분류 목록 */}
                  {large.children.length === 0 ? (
                    <p style={{ color: '#aaa', fontSize: '13px', margin: '8px 0' }}>중분류가 없어요. 추가해주세요!</p>
                  ) : (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                      {large.children.map((medium) => (
                        <div key={medium.name} style={{ background: '#f9fbe7', borderRadius: '8px', border: '1px solid #e0e0e0', overflow: 'hidden' }}>

                          {/* 중분류 헤더 */}
                          <div style={{ padding: '10px 14px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: '#e8f5e9' }}>
                            <span
                              style={{ fontWeight: '500', cursor: 'pointer', fontSize: '14px', color: '#2e7d32' }}
                              onClick={() => setOpenMedium(openMedium === `${large.name}-${medium.name}` ? null : `${large.name}-${medium.name}`)}
                            >
                              {openMedium === `${large.name}-${medium.name}` ? '▼' : '▶'} 📂 {medium.name}
                            </span>
                            <button onClick={() => handleDeleteMedium(large.name, medium.name)} style={{ background: '#e53935', color: 'white', border: 'none', borderRadius: '6px', padding: '4px 10px', cursor: 'pointer', fontSize: '12px' }}>
                              삭제
                            </button>
                          </div>

                          {openMedium === `${large.name}-${medium.name}` && (
                            <div style={{ padding: '12px 14px' }}>

                              {/* 소분류 추가 */}
                              <div style={{ display: 'flex', gap: '8px', marginBottom: '10px' }}>
                                <input
                                  value={form.small}
                                  onChange={(e) => setForm({ ...form, small: e.target.value })}
                                  placeholder="소분류 이름 (예: 채소)"
                                  style={{ flex: 1, padding: '7px 12px', borderRadius: '8px', border: '1px solid #c8e6c9', fontSize: '13px' }}
                                />
                                <button onClick={() => handleAddSmall(large.name, medium.name)} style={{ padding: '7px 14px', background: '#4caf50', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '13px' }}>
                                  소분류 추가
                                </button>
                              </div>

                              {/* 소분류 목록 */}
                              {medium.children.length === 0 ? (
                                <p style={{ color: '#aaa', fontSize: '13px', margin: 0 }}>소분류가 없어요. 추가해주세요!</p>
                              ) : (
                                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                                  {medium.children.map((small) => (
                                    <div key={small} style={{ background: 'white', border: '1px solid #c8e6c9', borderRadius: '20px', padding: '5px 12px', display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px' }}>
                                      <span>🏷️ {small}</span>
                                      <button onClick={() => handleDeleteSmall(large.name, medium.name, small)} style={{ background: 'none', border: 'none', color: '#e53935', cursor: 'pointer', fontSize: '14px', padding: '0', lineHeight: 1 }}>✕</button>
                                    </div>
                                  ))}
                                </div>
                              )}
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default CategoryManager;
